import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { doc, getDoc } from 'firebase/firestore';
import { db } from '../utils/firebase';
import AvailabilityGrid from '../components/AvailabilityGrid';

export default function Poll() {
  const { id } = useParams();
  const [poll, setPoll] = useState(null);

  useEffect(() => {
    const fetchPoll = async () => {
      const ref = doc(db, 'polls', id);
      const snap = await getDoc(ref);
      if (snap.exists()) {
        setPoll(snap.data());
      } else {
        setPoll({ error: 'Poll not found' });
      }
    };
    fetchPoll();
  }, [id]);

  if (!poll) return <div className="p-4">Loading...</div>;

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center p-4">
      {poll.error ? (
        <h1 className="text-xl text-red-500">{poll.error}</h1>
      ) : (
        <>
          <h1 className="text-3xl font-bold mb-4">{poll.name}</h1>
          <p className="text-gray-600 mb-6">Poll ID: {id}</p>
          <AvailabilityGrid pollId={id} />
        </>
      )}
    </div>
  );
}
